import{_ as e,o as a,c as l,a2 as n}from"./chunks/framework.BQ1gajhD.js";const p=JSON.parse('{"title":"天坛公园","description":"","frontmatter":{},"headers":[],"relativePath":"parks/temple-heaven.md","filePath":"parks/temple-heaven.md","lastUpdated":1784720050000}'),r={name:"parks/temple-heaven.md"};function s(o,t,d,i,g,h){return a(),l("div",null,[...t[0]||(t[0]=[n('<h1 id="天坛公园" tabindex="-1">天坛公园 <a class="header-anchor" href="#天坛公园" aria-label="Permalink to &quot;天坛公园&quot;">​</a></h1><blockquote><p>&quot;明清祭天圣地，世界文化遗产。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>天坛公园位于北京市东城区，是明清两代皇帝&quot;祭天&quot;&quot;祈谷&quot;的场所。天坛占地约273公顷，是中国现存最大的古代祭祀建筑群，1998年被联合国教科文组织列入《世界遗产名录》。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">6:00-22:00（公园），8:00-17:30（景点）</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">门票10元，联票28元（含祈年殿、回音壁、圜丘）</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">3-4小时</td></tr><tr><td style="text-align:left;"><strong>最佳季节</strong></td><td style="text-align:left;">四季皆宜</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁5号线天坛东门站</td></tr><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市东城区天坛东里甲1号</td></tr></tbody></table><h2 id="子景点导览" tabindex="-1">子景点导览 <a class="header-anchor" href="#子景点导览" aria-label="Permalink to &quot;子景点导览&quot;">​</a></h2><p>天坛拥有多处举世闻名的建筑，每一处都体现了中国古代&quot;敬天法祖&quot;的哲学思想：</p><table tabindex="0"><thead><tr><th style="text-align:left;">子景点</th><th style="text-align:left;">特色</th><th style="text-align:left;">详情</th></tr></thead><tbody><tr><td style="text-align:left;">🏛️ <strong>祈年殿</strong></td><td style="text-align:left;">天坛标志，三重檐圆形大殿</td><td style="text-align:left;"><a href="/beijing-travel-guide/landmarks/temple-of-heaven/qinian-dian.html">查看详情 →</a></td></tr><tr><td style="text-align:left;">🔵 <strong>圜丘坛</strong></td><td style="text-align:left;">冬至祭天之所，九重天数</td><td style="text-align:left;"><a href="/beijing-travel-guide/landmarks/temple-of-heaven/huanqiu-tan.html">查看详情 →</a></td></tr><tr><td style="text-align:left;">🔊 <strong>皇穹宇与回音壁</strong></td><td style="text-align:left;">声学奇迹，贴墙传声</td><td style="text-align:left;"><a href="/beijing-travel-guide/landmarks/temple-of-heaven/huangqiong-yu.html">查看详情 →</a></td></tr><tr><td style="text-align:left;">🛤️ <strong>丹陛桥</strong></td><td style="text-align:left;">360米神路，步步登高</td><td style="text-align:left;"><a href="/beijing-travel-guide/landmarks/temple-of-heaven/danbi-qiao.html">查看详情 →</a></td></tr><tr><td style="text-align:left;">🏠 <strong>斋宫</strong></td><td style="text-align:left;">皇帝斋戒之所，无梁殿</td><td style="text-align:left;"><a href="/beijing-travel-guide/landmarks/temple-of-heaven/zhai-gong.html">查看详情 →</a></td></tr><tr><td style="text-align:left;">🎵 <strong>神乐署</strong></td><td style="text-align:left;">皇家音乐学院，中和韶乐</td><td style="text-align:left;"><a href="/beijing-travel-guide/landmarks/temple-of-heaven/shenyue-shu.html">查看详情 →</a></td></tr></tbody></table><h2 id="推荐路线" tabindex="-1">推荐路线 <a class="header-anchor" href="#推荐路线" aria-label="Permalink to &quot;推荐路线&quot;">​</a></h2><p><strong>精华路线（约3小时）</strong>：</p><p>南门 → 圜丘坛 → 皇穹宇（回音壁） → 丹陛桥 → 祈年殿 → 皇乾殿 → 北门</p><p><strong>深度路线（约4-5小时）</strong>：</p><p>南门 → 昭亨门 → 圜丘坛 → 皇穹宇 → 回音壁 → 丹陛桥 → 祈年殿 → 皇乾殿 → 斋宫 → 神乐署 → 西门</p><h2 id="实用贴士" tabindex="-1">实用贴士 <a class="header-anchor" href="#实用贴士" aria-label="Permalink to &quot;实用贴士&quot;">​</a></h2><ol><li><strong>门票选择</strong>：建议购买联票（28元），否则看不到祈年殿等精华景点</li><li><strong>最佳时间</strong>：早上7:30前入园可以避开人流，还能看到晨练的老人</li><li><strong>拍照位置</strong>：祈年殿正面台阶处、圜丘坛中心都是绝佳拍照点</li><li><strong>回音壁</strong>：现在为了保护文物，回音壁已被围栏隔开，回音效果不如从前</li><li><strong>附近美食</strong>：南门涮肉（老北京铜锅涮肉）就在天坛南门对面，非常推荐</li></ol><hr><p><strong>📍 地址</strong>：北京市东城区天坛东里甲1号 <strong>📞 电话</strong>：010-67028866 <strong>🌐 官网</strong>：<a href="http://www.tiantanpark.com" target="_blank" rel="noreferrer">www.tiantanpark.com</a></p><p><strong>💡 完整导览</strong>：<a href="/beijing-travel-guide/landmarks/temple-of-heaven/">天坛详细介绍与全部子景点 →</a></p>',19)])])}const x=e(r,[["render",s]]);export{p as __pageData,x as default};
